<div class="treeview">
*<''behavior_pack''>
**spawn_rules
</div>
==数据结构==
===组件结构===
<div class="treeview">
*{{json|object|minecraft:spawns_on_surface}}:''可生成于地面''
*{{json|object|minecraft:spawns_underground}}:''可生成于地底''
*{{json|object|minecraft:brightness_filter}}:''生成亮度过滤器''
**{{json|array|max}}:最大值
**{{json|array|min}}:最小值
**{{json|boolean|adjust_for_weather}}
*{{json|object|minecraft:difficulty_filter}}:''生成难度过滤器''
**{{json|array|max}}:最大值
**{{json|array|min}}:最小值
*{{json|object|minecraft:weight}}:''生成权重''
**{{json|array|default}}:''权重值''
*{{json|object|minecraft:herd}}:''生成实体群居数量''
**{{json|array|max}}:最大值
**{{json|array|min}}:最小值
*{{json|object|minecraft:permute_type}}:''生成实体取代类型''
**
***{{json|array|weight}}:''权重''
**
***{{json|array|weight}}:''权重''
***{{json|object|entity_type}}:''取代实体类型''
*{{json|object|minecraft:minecraft:biome_filter}}:''生成群系过滤器''
**{{json|object|test}}:''生成群系规则''
***
</div>


==语法==
<syntaxhighlight lang="json" line>
//复制于——原版僵尸文件(BH/spawn_rules/zombie.json)
{
    "format_version": "1.8.0",//版本号
    "minecraft:spawn_rules": {
      "description": {
        "identifier": "minecraft:zombie",
        "population_control": "monster"
      },//描述
      "conditions": [
        {
          "minecraft:spawns_on_surface": {},//地面生成
          "minecraft:spawns_underground": {},//地底生成
          "minecraft:brightness_filter": {
            "min": 0,
            "max": 7,
            "adjust_for_weather": true
          },//生成亮度过滤器
          "minecraft:difficulty_filter": {
            "min": "easy",
            "max": "hard"
          },//生成难度过滤器
          "minecraft:weight": {
            "default": 100
          },//生成权重
          "minecraft:herd": {
            "min_size": 2,
            "max_size": 4
          },//生成实体群居数量
          "minecraft:permute_type": [
            {
                  "weight": 95
            },
            {
              "weight": 5,
              "entity_type": "minecraft:zombie_villager"
            }
          ],//生成实体取代类型
          "minecraft:biome_filter": {
            "test": "has_biome_tag", "operator": "==", "value": "monster"
          }//生成群系过滤器
        }
      ]
    }
  }
</syntaxhighlight>

