    "components": {
      "minecraft:unit_cube": {},
      "minecraft:on_interact": {
        "event": "example:event"
      }
    },
    "events": {
      "example:event": {
        "run_command": "say HelloWorld"
      }
    }
  }
}
</syntaxhighlight>

